import { RiArrowDownSLine, RiArrowUpSLine } from 'react-icons/ri';
import { MoviesInformation } from '../home-page';

export function LoadMoreButton(theme: any, onClick: any, gridVisibility: boolean, movieData: MoviesInformation) {
	return (
		<button className={`flex flex-col text-center items-center w-screen justify-center text-5xl ${theme.themeBgClassName}`} onClick={onClick(movieData.type)}>
			{!gridVisibility ? <RiArrowDownSLine /> : <RiArrowUpSLine />}
		</button>
	);
}
